def _validate_socket(
    sock_or_fd: socket.socket | int,
    sock_type: socket.SocketKind,
    addr_family: socket.AddressFamily = socket.AF_UNSPEC,
    *,
    require_connected: bool = False,
    require_bound: bool = False,
) -> socket.socket:
    """
    Validate that the given object refers to a socket meeting the requested
    requirements and return a non-blocking socket.socket instance.

    Parameters:
    - sock_or_fd: either a socket.socket instance or an integer file descriptor
      referring to a socket.
    - sock_type: the required socket type (for example socket.SOCK_STREAM).
    - addr_family: the required address family (for example socket.AF_INET).
      Defaults to AF_UNSPEC to allow any family.
    - require_connected: if True, the socket must be connected to a peer.
    - require_bound: if True, the socket must be bound to a local address.

    Raises:
    - TypeError: if sock_or_fd is neither an int nor a socket.socket.
    - ValueError: when the socket does not satisfy the required constraints.
    - OSError: for underlying socket errors when constructing from a file
      descriptor.
    """
    if isinstance(sock_or_fd, int):
        try:
            sock = socket.socket(fileno=sock_or_fd)
        except OSError as exc:
            if exc.errno == errno.ENOTSOCK:
                raise ValueError(
                    "the file descriptor does not refer to a socket"
                ) from exc
            elif require_connected:
                raise ValueError("the socket must be connected") from exc
            elif require_bound:
                raise ValueError("the socket must be bound to a local address") from exc
            else:
                raise
    elif isinstance(sock_or_fd, socket.socket):
        sock = sock_or_fd
    else:
        raise TypeError(
            f"expected an int or socket, got {type(sock_or_fd).__qualname__} instead"
        )

    try:
        if require_connected:
            try:
                sock.getpeername()
            except OSError as exc:
                raise ValueError("the socket must be connected") from exc

        if require_bound:
            try:
                if sock.family in (socket.AF_INET, socket.AF_INET6):
                    bound_addr = sock.getsockname()[1]
                else:
                    bound_addr = sock.getsockname()
            except OSError:
                bound_addr = None

            if not bound_addr:
                raise ValueError("the socket must be bound to a local address")

        if addr_family != socket.AF_UNSPEC and sock.family != addr_family:
            raise ValueError(
                f"address family mismatch: expected {addr_family.name}, got "
                f"{sock.family.name}"
            )

        if sock.type != sock_type:
            raise ValueError(
                f"socket type mismatch: expected {sock_type.name}, got {sock.type.name}"
            )
    except BaseException:
        # Avoid ResourceWarning from the locally constructed socket object
        if isinstance(sock_or_fd, int):
            sock.detach()

        raise

    sock.setblocking(False)
    return sock


class SocketAttribute(TypedAttributeSet):
    """
    .. attribute:: family
        :type: socket.AddressFamily

        the address family of the underlying socket

    .. attribute:: local_address
        :type: tuple[str, int] | str

        the local address the underlying socket is connected to

    .. attribute:: local_port
        :type: int

        for IP based sockets, the local port the underlying socket is bound to

    .. attribute:: raw_socket
        :type: socket.socket

        the underlying stdlib socket object

    .. attribute:: remote_address
        :type: tuple[str, int] | str

        the remote address the underlying socket is connected to

    .. attribute:: remote_port
        :type: int

        for IP based sockets, the remote port the underlying socket is connected to
    """

    @abstractmethod
    def extra_attributes(self) -> Mapping[str, object]:
        """
        Return additional socket-related attributes as a mapping.

        Implementations should return a dictionary-like mapping containing
        any extra attributes that are associated with the socket wrapper. The
        mapping keys should be strings naming the attributes, and the values
        should be the corresponding attribute values.

        This abstract method exists to allow subclasses to provide extra
        diagnostic or metadata attributes beyond the common ones described in
        the class documentation.
        """
        raise NotImplementedError


def _raw_socket(sock_or_fd: socket.socket | int) -> socket.socket:
    """
    Obtain a socket.socket instance from either a socket object or an integer
    file descriptor.

    This function will validate the input and return a non-blocking
    socket.socket instance. If a file descriptor is provided and the function
    constructs a socket.socket object locally, it ensures the descriptor is
    properly converted and that resource ownership is handled.

    Parameters:
    - sock_or_fd: a socket.socket instance or an integer file descriptor.

    Returns:
    - a non-blocking socket.socket corresponding to the provided argument.

    Note: callers that construct a socket.socket from a raw file descriptor
    should ensure they manage its lifetime appropriately; this helper sets
    the socket to non-blocking mode before returning it.
    """
    # Default to validating as a generic stream socket, but keep flexibility by
    # allowing any address family.
    return _validate_socket(
        sock_or_fd,
        sock_type=socket.SOCK_STREAM,
        addr_family=socket.AF_UNSPEC,
        require_connected=False,
        require_bound=False,
    )